mapper.insert:
/* com.matjzing.mapper.SwaggerUserMapper.insertSwaggerUser */
INSERT INTO SWAGGER_MEMBER (
	  ID /*ID*/
	, PASSWORD /*비밀번호*/
	, NAME /*이름*/
	, USE_YN /*사용_여부*/
	, REGISTER_SEQ /*등록자_시퀀스*/
	, REGISTER_IP /*등록자_아이피*/
	, REGISTRATION_DT /*등록_일시*/
	, UPDATER_SEQ /*수정자_시퀀스*/
	, UPDATER_IP /*수정자_아이피*/
	, UPDATE_DT /*수정_일시*/
) VALUES (
	  #{id}
	, #{password}
	, #{name}
	, TRUE
	, #{registerSeq}
	, #{registerIp}
	, NOW(3)
	, #{updaterSeq}
	, #{updaterIp}
	, NOW(3)
)

mapper.update:
		/* com.matjzing.mapper.SwaggerUserMapper.updateSwaggerUser */
    	UPDATE SWAGGER_MEMBER SET
			  UPDATER_SEQ = #{updaterSeq}
			, UPDATER_IP = #{updaterIp} /*수정자_아이피*/
			, UPDATE_DT = NOW(3)
			, PASSWORD = #{password} /*비밀번호*/
		WHERE
			MEMBER_SEQ = #{memberSeq}

		/* com.matjzing.mapper.SwaggerUserMapper.deleteSwaggerUser */
    	UPDATE SWAGGER_MEMBER SET
			  UPDATER_SEQ = #{updaterSeq}
			, UPDATER_IP = #{updaterIp} /*수정자_아이피*/
			, UPDATE_DT = NOW(3)
			, USE_YN = FALSE
		WHERE
			MEMBER_SEQ = #{memberSeq}

mapper.select:
/* com.matjzing.SwaggerUserMapper.selectLogin */
SELECT
	MEMBER_SEQ /*회원_시퀀스*/
FROM
	SWAGGER_MEMBER
WHERE
	USE_YN = TRUE
	AND ID = #{id}
	AND PASSWORD = #{password}
